const express = require('express');
const cors = require('cors');
const { createProxyMiddleware } = require('http-proxy-middleware');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Secure CORS Configuration ---
// Instead of Access-Control-Allow-Origin: *, use an explicit allowlist of trusted origins.
// Wildcard CORS allows any website to make authenticated requests to your API,
// enabling CSRF-like attacks, data exfiltration, and abuse from malicious origins.

const ALLOWED_ORIGINS = [
  // Local development
  'http://localhost:3000',
  'http://localhost:3001',
  'http://localhost:5173',
  'http://127.0.0.1:3000',
  // Staging
  'https://staging.example.com',
  'https://staging-admin.example.com',
  // Production
  'https://www.example.com',
  'https://app.example.com',
  'https://admin.example.com',
];

// Allow additional origins via environment variable (comma-separated)
if (process.env.ADDITIONAL_ALLOWED_ORIGINS) {
  const additional = process.env.ADDITIONAL_ALLOWED_ORIGINS.split(',').map(o => o.trim());
  ALLOWED_ORIGINS.push(...additional);
}

const corsOptions = {
  origin: function (origin, callback) {
    // Allow requests with no origin (e.g., server-to-server, curl, mobile apps)
    // In production, you may want to restrict this further
    if (!origin) {
      return callback(null, true);
    }
    if (ALLOWED_ORIGINS.includes(origin)) {
      return callback(null, origin);
    }
    return callback(new Error(`Origin ${origin} not allowed by CORS policy`));
  },
  methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
  allowedHeaders: [
    'Content-Type',
    'Authorization',
    'X-Requested-With',
    'X-Request-ID',
    'Accept',
    'Origin',
  ],
  exposedHeaders: ['X-Request-ID', 'X-RateLimit-Remaining'],
  credentials: true,
  maxAge: 600, // Cache preflight for 10 minutes
  optionsSuccessStatus: 204,
};

// --- Security Middleware ---
app.use(helmet());

// Rate limiting to prevent abuse
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 1000, // limit each IP to 1000 requests per windowMs
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// Apply secure CORS
app.use(cors(corsOptions));

// Handle CORS errors gracefully
app.use((err, req, res, next) => {
  if (err.message && err.message.includes('not allowed by CORS policy')) {
    return res.status(403).json({ error: 'CORS: Origin not allowed' });
  }
  next(err);
});

// Parse JSON bodies with size limit
app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true, limit: '1mb' }));

// --- Request ID Middleware ---
const { randomUUID } = require('crypto');
app.use((req, res, next) => {
  req.requestId = req.headers['x-request-id'] || randomUUID();
  res.setHeader('X-Request-ID', req.requestId);
  next();
});

// --- Logging Middleware ---
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - start;
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      requestId: req.requestId,
      method: req.method,
      path: req.path,
      origin: req.headers.origin || 'none',
      status: res.statusCode,
      duration: `${duration}ms`,
      ip: req.ip,
    }));
  });
  next();
});

// --- Backend Service Registry ---
const SERVICES = {
  '/api/users': {
    target: process.env.USER_SERVICE_URL || 'http://localhost:4001',
    pathRewrite: { '^/api/users': '/users' },
  },
  '/api/products': {
    target: process.env.PRODUCT_SERVICE_URL || 'http://localhost:4002',
    pathRewrite: { '^/api/products': '/products' },
  },
  '/api/orders': {
    target: process.env.ORDER_SERVICE_URL || 'http://localhost:4003',
    pathRewrite: { '^/api/orders': '/orders' },
  },
  '/api/auth': {
    target: process.env.AUTH_SERVICE_URL || 'http://localhost:4004',
    pathRewrite: { '^/api/auth': '/auth' },
  },
};

// --- Proxy Setup ---
for (const [route, config] of Object.entries(SERVICES)) {
  app.use(
    route,
    createProxyMiddleware({
      target: config.target,
      changeOrigin: true,
      pathRewrite: config.pathRewrite,
      timeout: 10000,
      proxyTimeout: 10000,
      onProxyReq: (proxyReq, req) => {
        // Forward request ID to downstream services
        proxyReq.setHeader('X-Request-ID', req.requestId);
        // Remove hop-by-hop headers
        proxyReq.removeHeader('cookie'); // Don't forward cookies to internal services blindly
      },
      onError: (err, req, res) => {
        console.error(JSON.stringify({
          timestamp: new Date().toISOString(),
          requestId: req.requestId,
          error: 'Proxy error',
          target: config.target,
          message: err.message,
        }));
        if (!res.headersSent) {
          res.status(502).json({
            error: 'Bad Gateway',
            message: 'The upstream service is unavailable.',
            requestId: req.requestId,
          });
        }
      },
    })
  );
}

// --- Health Check ---
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    services: Object.keys(SERVICES),
  });
});

// --- CORS Debug Endpoint (non-production only) ---
if (process.env.NODE_ENV !== 'production') {
  app.get('/debug/cors', (req, res) => {
    res.json({
      allowedOrigins: ALLOWED_ORIGINS,
      requestOrigin: req.headers.origin || 'none',
    });
  });
}

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({
    error: 'Not Found',
    message: `Route ${req.method} ${req.path} not found`,
    requestId: req.requestId,
  });
});

// --- Global Error Handler ---
app.use((err, req, res, _next) => {
  console.error(JSON.stringify({
    timestamp: new Date().toISOString(),
    requestId: req.requestId,
    error: err.message,
    stack: process.env.NODE_ENV !== 'production' ? err.stack : undefined,
  }));

  if (!res.headersSent) {
    res.status(err.status || 500).json({
      error: 'Internal Server Error',
      message: process.env.NODE_ENV !== 'production' ? err.message : 'An unexpected error occurred',
      requestId: req.requestId,
    });
  }
});

// --- Start Server ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
  console.log(`Environment: ${process.env.NODE_ENV || 'development'}`);
  console.log(`Allowed CORS origins: ${ALLOWED_ORIGINS.join(', ')}`);
  console.log('Registered routes:');
  for (const [route, config] of Object.entries(SERVICES)) {
    console.log(`  ${route} -> ${config.target}`);
  }
});

module.exports = app;